// DESIGN SYSTEM
// ═══════════════════════════════════════════════════════════════════════════

const BG_URL = "/forest-bg.png";

const C = {
  primary: "#C65D3B",
  secondary: "#E9B872",
  text: "#F5EDE0",
  textSoft: "rgba(245,237,224,0.76)",
  textMute: "rgba(245,237,224,0.52)",
  accent: "#6B8F8A",
  cta: "#B8402E",
  light: "#FDF6F0",
  deep: "#0D1A0F",
};

const fontsCSS = `@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400;1,500;1,600&family=Outfit:wght@200;300;400;500;600;700&family=DM+Mono:wght@300;400;500&display=swap');`;

const globalCSS = `
*, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }
html { scroll-behavior:smooth; }
body {
  background: #0D1A0F;
  color: ${C.text};
  font-family: 'Outfit', sans-serif;
  overflow-x: hidden;
  cursor: none;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
a, button { cursor: none; }

::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: rgba(13,26,15,0.5); }
::-webkit-scrollbar-thumb { background: ${C.primary}; border-radius: 4px; }

.serif { font-family: 'Cormorant Garamond', serif; letter-spacing: -0.01em; }
.mono { font-family: 'DM Mono', monospace; }

/* Background layer */
.bg-fixed {
  position: fixed;
  inset: 0;
  background-image: url('${BG_URL}');
  background-size: cover;
  background-position: center;
  background-attachment: fixed;
  z-index: -2;
}
.bg-tint {
  position: fixed;
  inset: 0;
  background: linear-gradient(180deg, rgba(8,18,10,0.28) 0%, rgba(8,18,10,0.50) 100%);
  z-index: -1;
  pointer-events: none;
}

/* Glowing orb cursor */
.cursor-orb {
  position: fixed;
  top: 0; left: 0;
  width: 24px; height: 24px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(198,93,59,0.9) 0%, rgba(198,93,59,0.4) 40%, rgba(233,184,114,0.1) 70%, transparent 100%);
  pointer-events: none;
  z-index: 99999;
  transform: translate(-50%, -50%);
  mix-blend-mode: normal;
  transition: width 0.3s cubic-bezier(0.16,1,0.3,1), height 0.3s cubic-bezier(0.16,1,0.3,1);
  filter: blur(0.5px);
  box-shadow:
    0 0 20px rgba(198,93,59,0.6),
    0 0 40px rgba(198,93,59,0.3),
    0 0 60px rgba(233,184,114,0.2);
}
.cursor-orb.hover {
  width: 56px; height: 56px;
  background: radial-gradient(circle, rgba(233,184,114,0.9) 0%, rgba(198,93,59,0.5) 40%, rgba(198,93,59,0.15) 70%, transparent 100%);
  box-shadow:
    0 0 30px rgba(233,184,114,0.7),
    0 0 60px rgba(198,93,59,0.4),
    0 0 90px rgba(233,184,114,0.25);
}
.cursor-trail {
  position: fixed;
  top: 0; left: 0;
  width: 8px; height: 8px;
  border-radius: 50%;
  background: ${C.secondary};
  pointer-events: none;
  z-index: 99998;
  transform: translate(-50%, -50%);
  opacity: 0.6;
  box-shadow: 0 0 12px rgba(233,184,114,0.8);
}

@media (pointer: coarse) {
  body { cursor: auto; }
  a, button { cursor: pointer; }
  .cursor-orb, .cursor-trail { display: none; }
}

/* Animations */
@keyframes fadeUp { from { opacity:0; transform: translateY(30px); } to { opacity:1; transform: translateY(0); } }
@keyframes fadeIn { from { opacity:0; } to { opacity:1; } }
@keyframes slideRight { from { opacity:0; transform: translateX(-40px); } to { opacity:1; transform: translateX(0); } }
@keyframes float { 0%,100% { transform: translateY(0) rotate(0deg); } 50% { transform: translateY(-14px) rotate(1deg); } }
@keyframes floatSlow { 0%,100% { transform: translateY(0); } 50% { transform: translateY(-8px); } }
@keyframes rotateSlow { to { transform: rotate(360deg); } }
@keyframes rotateReverse { to { transform: rotate(-360deg); } }
@keyframes marquee { to { transform: translateX(-50%); } }
@keyframes shimmer { 0%{ background-position: -200% center; } 100%{ background-position: 200% center; } }
@keyframes pulseBorder { 0%,100% { box-shadow: 0 0 0 0 rgba(198,93,59,0.3); } 50% { box-shadow: 0 0 0 12px rgba(198,93,59,0); } }
@keyframes glowPulse { 0%,100% { filter: drop-shadow(0 0 16px rgba(233,184,114,0.3)); } 50% { filter: drop-shadow(0 0 32px rgba(233,184,114,0.6)); } }

.fadeUp { animation: fadeUp 0.9s cubic-bezier(0.16,1,0.3,1) forwards; opacity:0; }
.fadeIn { animation: fadeIn 0.7s ease forwards; opacity:0; }
.slideRight { animation: slideRight 0.9s cubic-bezier(0.16,1,0.3,1) forwards; opacity:0; }

/* GLASS SYSTEM — forest edition */
.glass {
  background: rgba(245, 237, 224, 0.13);
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  border: 1px solid rgba(245, 237, 224, 0.22);
  box-shadow:
    0 8px 32px rgba(0, 0, 0, 0.32),
    inset 0 1px 0 rgba(255, 255, 255, 0.16),
    inset 0 -1px 0 rgba(198, 93, 59, 0.1);
  border-radius: 20px;
}
.glass-heavy {
  background: rgba(245, 237, 224, 0.17);
  backdrop-filter: blur(32px) saturate(200%);
  -webkit-backdrop-filter: blur(32px) saturate(200%);
  border: 1px solid rgba(245, 237, 224, 0.26);
  box-shadow:
    0 16px 48px rgba(0, 0, 0, 0.38),
    inset 0 2px 0 rgba(255, 255, 255, 0.2),
    inset 0 -2px 0 rgba(198, 93, 59, 0.12);
  border-radius: 24px;
}
.glass-frost {
  background: rgba(245, 237, 224, 0.07);
  backdrop-filter: blur(16px) saturate(160%);
  -webkit-backdrop-filter: blur(16px) saturate(160%);
  border: 1px solid rgba(245, 237, 224, 0.14);
  box-shadow:
    0 4px 24px rgba(0, 0, 0, 0.24),
    inset 0 1px 0 rgba(255, 255, 255, 0.1);
  border-radius: 16px;
}
.glass-dark {
  background: rgba(31, 42, 36, 0.55);
  backdrop-filter: blur(28px) saturate(180%);
  -webkit-backdrop-filter: blur(28px) saturate(180%);
  border: 1px solid rgba(253, 246, 240, 0.12);
  box-shadow:
    0 16px 48px rgba(0, 0, 0, 0.25),
    inset 0 1px 0 rgba(253, 246, 240, 0.12);
  border-radius: 20px;
}
.glass-gold {
  background: linear-gradient(135deg, rgba(233,184,114,0.25), rgba(198,93,59,0.15));
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  border: 1px solid rgba(233,184,114,0.45);
  box-shadow:
    0 8px 32px rgba(198, 93, 59, 0.15),
    inset 0 1px 0 rgba(253, 246, 240, 0.5);
  border-radius: 20px;
}

/* BUTTONS */
.btn-primary {
  background: ${C.cta};
  color: ${C.light};
  border: none;
  padding: 15px 34px;
  font-family: 'Outfit', sans-serif;
  font-weight: 600; font-size: 13px;
  letter-spacing: 0.12em; text-transform: uppercase;
  border-radius: 100px;
  transition: all 0.3s cubic-bezier(0.16,1,0.3,1);
  display: inline-flex; align-items: center; gap: 10px;
  text-decoration: none;
  position: relative; overflow: hidden;
  box-shadow: 0 8px 24px rgba(184,64,46,0.25), inset 0 1px 0 rgba(255,255,255,0.2);
}
.btn-primary::before {
  content: ''; position: absolute; inset: 0;
  background: linear-gradient(135deg, transparent, rgba(255,255,255,0.2), transparent);
  transform: translateX(-100%);
  transition: transform 0.6s;
}
.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 16px 40px rgba(184,64,46,0.4), inset 0 1px 0 rgba(255,255,255,0.3);
}
.btn-primary:hover::before { transform: translateX(100%); }

.btn-ghost {
  background: rgba(245,237,224,0.1);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  color: ${C.text};
  border: 1px solid rgba(245,237,224,0.28);
  padding: 14px 30px;
  font-family: 'Outfit', sans-serif;
  font-weight: 500; font-size: 13px;
  letter-spacing: 0.06em;
  border-radius: 100px;
  transition: all 0.3s ease;
  text-decoration: none;
  display: inline-flex; align-items: center; gap: 8px;
}
.btn-ghost:hover {
  background: rgba(245,237,224,0.22);
  color: ${C.light};
  border-color: rgba(245,237,224,0.5);
  transform: translateY(-2px);
}

/* PILLS */
.pill {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 6px 16px;
  border-radius: 100px;
  font-size: 11px; font-weight: 500;
  letter-spacing: 0.08em;
  background: rgba(245,237,224,0.12);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(198,93,59,0.38);
  color: ${C.primary};
  text-transform: uppercase;
}
.pill-dark {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 6px 16px;
  border-radius: 100px;
  font-size: 11px; font-weight: 500;
  letter-spacing: 0.08em;
  background: rgba(253,246,240,0.12);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border: 1px solid rgba(253,246,240,0.2);
  color: rgba(253,246,240,0.85);
  text-transform: uppercase;
}

/* EYEBROW */
.eyebrow {
  font-family: 'DM Mono', monospace;
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: ${C.accent};
  display: inline-flex;
  align-items: center;
  gap: 14px;
}
.eyebrow::before {
  content: ''; display: block;
  width: 36px; height: 1px;
  background: currentColor;
}

/* IMAGE ZOOM */
.img-wrap {
  overflow: hidden;
  position: relative;
  background: rgba(198,93,59,0.05);
}
.img-wrap img {
  width: 100%; height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.7s cubic-bezier(0.16,1,0.3,1), filter 0.7s;
}
.img-wrap:hover img {
  transform: scale(1.06);
}

/* Card hover lift */
.lift {
  transition: transform 0.4s cubic-bezier(0.16,1,0.3,1), box-shadow 0.4s;
}
.lift:hover {
  transform: translateY(-6px);
}

/* Shimmer text */
.shimmer {
  background: linear-gradient(90deg, ${C.primary}, ${C.secondary}, ${C.primary});
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  animation: shimmer 4s linear infinite;
}

/* ORB DECORATIONS */
.orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  filter: blur(20px);
}

/* Responsive */
@media (max-width: 900px) {
  .hide-mob { display: none !important; }
  .mob-col { flex-direction: column !important; }
  .mob-full { width: 100% !important; grid-template-columns: 1fr !important; }
  .mob-p { padding: 28px 20px !important; }
  .mob-center { text-align: center !important; align-items: center !important; }
  .mob-text-sm { font-size: clamp(32px, 9vw, 48px) !important; }
  .pad-side { padding-left: 20px !important; padding-right: 20px !important; }
}
`;

