// CURSOR
// ═══════════════════════════════════════════════════════════════════════════

function Cursor() {
  const orb = useRef(null);
  const trail = useRef(null);
  const mouse = useRef({ x: 0, y: 0 });
  const orbPos = useRef({ x: 0, y: 0 });
  const trailPos = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const move = e => { mouse.current = { x: e.clientX, y: e.clientY }; };
    window.addEventListener("mousemove", move);

    const over = e => {
      if (e.target.closest("a, button, .hoverable")) {
        orb.current?.classList.add("hover");
      } else {
        orb.current?.classList.remove("hover");
      }
    };
    window.addEventListener("mouseover", over);

    let raf;
    const animate = () => {
      orbPos.current.x += (mouse.current.x - orbPos.current.x) * 0.18;
      orbPos.current.y += (mouse.current.y - orbPos.current.y) * 0.18;
      trailPos.current.x += (mouse.current.x - trailPos.current.x) * 0.08;
      trailPos.current.y += (mouse.current.y - trailPos.current.y) * 0.08;
      if (orb.current) {
        orb.current.style.left = orbPos.current.x + "px";
        orb.current.style.top = orbPos.current.y + "px";
      }
      if (trail.current) {
        trail.current.style.left = trailPos.current.x + "px";
        trail.current.style.top = trailPos.current.y + "px";
      }
      raf = requestAnimationFrame(animate);
    };
    animate();

    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseover", over);
      cancelAnimationFrame(raf);
    };
  }, []);

  return (
    <>
      <div ref={trail} className="cursor-trail" />
      <div ref={orb} className="cursor-orb" />
    </>
  );
}

