// PILL NAV (persistent across all pages)
// ═══════════════════════════════════════════════════════════════════════════


function PillNav({ page, setPage, navigateTo }) {
  const [active, setActive] = useState("Home");

  useEffect(() => {
    if (page !== "home") return;
    const ids = ["top", "story", "work", "skills", "contact"];
    const map = { top: "Home", story: "Story", work: "Work", skills: "Skills", contact: "Contact" };

    const update = () => {
      const trigger = window.innerHeight * 0.35;
      let current = ids[0];
      for (const id of ids) {
        const el = document.getElementById(id);
        if (el && el.getBoundingClientRect().top <= trigger) current = id;
      }
      setActive(map[current]);
    };

    window.addEventListener("scroll", update, { passive: true });
    update();
    return () => window.removeEventListener("scroll", update);
  }, [page]);

  const items = ["Home", "Story", "Work", "Skills", "Contact"];

  const handleClick = (item) => {
    setActive(item);
    const id = item.toLowerCase() === "home" ? "top" : item.toLowerCase();
    navigateTo(id);
  };

  return (
    <div style={{
      position: "fixed", bottom: 24, left: "50%", transform: "translateX(-50%)",
      zIndex: 90,
      background: "rgba(31,42,36,0.82)",
      backdropFilter: "blur(32px) saturate(180%)",
      WebkitBackdropFilter: "blur(32px) saturate(180%)",
      border: "1px solid rgba(233,184,114,0.25)",
      borderRadius: 100, padding: "8px 10px",
      display: "flex", gap: 4,
      boxShadow: `
        0 20px 60px rgba(31,42,36,0.3),
        0 0 40px rgba(198,93,59,0.15),
        inset 0 1px 0 rgba(255,255,255,0.08)
      `,
    }}>
      {items.map(item => (
        <button key={item} onClick={() => handleClick(item)} style={{
          background: active === item && page === "home" ? `linear-gradient(135deg, ${C.secondary}, ${C.primary})` : "transparent",
          color: active === item && page === "home" ? C.light : "rgba(253,246,240,0.55)",
          border: "none", borderRadius: 100,
          padding: active === item && page === "home" ? "9px 22px" : "9px 16px",
          fontFamily: "Outfit", fontSize: 12,
          fontWeight: active === item && page === "home" ? 600 : 400,
          letterSpacing: "0.05em",
          transition: "all 0.35s cubic-bezier(0.16,1,0.3,1)",
          whiteSpace: "nowrap",
          boxShadow: active === item && page === "home" ? `0 6px 18px rgba(198,93,59,0.4)` : "none",
        }}>{item}</button>
      ))}
    </div>
  );
}

