function Work({ setPage, setProjectId }) {
  return (
    <section id="work" style={{
      padding: "140px 48px",
      background: `linear-gradient(180deg, rgba(31,42,36,0.92), rgba(31,42,36,0.95))`,
      backdropFilter: "blur(20px)",
      WebkitBackdropFilter: "blur(20px)",
      position: "relative", overflow: "hidden",
    }} className="pad-side">
      <div className="orb" style={{ width: 700, height: 700, top: "50%", left: "50%", transform: "translate(-50%,-50%)", background: `${C.primary}20` }} />

      <div style={{ maxWidth: 1200, margin: "0 auto", position: "relative", zIndex: 2 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 24, marginBottom: 72 }}>
          <div>
            <div className="eyebrow" style={{ color: C.secondary, marginBottom: 24 }}>Product Case Studies</div>
            <h2 className="serif" style={{ fontSize: "clamp(40px, 6vw, 72px)", fontWeight: 400, lineHeight: 1.05, color: C.light }}>
              Five products.<br />
              <span style={{ fontStyle: "italic", background: `linear-gradient(135deg, ${C.secondary}, ${C.primary})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>
                Each one lived.
              </span>
            </h2>
          </div>
          <p style={{ fontSize: 14, color: "rgba(253,246,240,0.5)", maxWidth: 280, lineHeight: 1.7, fontWeight: 300 }}>
            Click any project for the full deep-dive — research methodology, business model, competitive landscape, and the story behind how it came to be.
          </p>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: 20 }}>
          {PROJECTS.map((p, i) => (
            <div key={p.id} onClick={() => { setProjectId(p.id); setPage("project"); window.scrollTo(0, 0); }}
              className="hoverable lift"
              style={{
                background: "rgba(253,246,240,0.04)",
                backdropFilter: "blur(24px) saturate(180%)",
                WebkitBackdropFilter: "blur(24px) saturate(180%)",
                border: "1px solid rgba(253,246,240,0.1)",
                borderRadius: 24, overflow: "hidden",
                transition: "all 0.4s cubic-bezier(0.16,1,0.3,1)",
                animation: `fadeUp 0.8s cubic-bezier(0.16,1,0.3,1) ${0.1 + i * 0.1}s both`,
              }}
              onMouseEnter={e => {
                e.currentTarget.style.background = "rgba(253,246,240,0.1)";
                e.currentTarget.style.borderColor = `${p.hex}70`;
                e.currentTarget.style.boxShadow = `0 30px 80px rgba(0,0,0,0.4), 0 0 60px ${p.hex}30`;
              }}
              onMouseLeave={e => {
                e.currentTarget.style.background = "rgba(253,246,240,0.04)";
                e.currentTarget.style.borderColor = "rgba(253,246,240,0.1)";
                e.currentTarget.style.boxShadow = "";
              }}
            >
              <div style={{ height: 3, background: `linear-gradient(90deg, ${p.hex}, ${C.secondary}80, transparent)` }} />

              <div style={{ padding: "32px 30px 26px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 22 }}>
                  <div>
                    <span className="pill-dark" style={{ marginBottom: 14, display: "inline-flex" }}>{p.year}</span>
                    <h3 className="serif" style={{ fontSize: 30, fontWeight: 600, color: C.light, lineHeight: 1.1, marginTop: 10 }}>{p.name}</h3>
                  </div>
                  <div style={{
                    width: 56, height: 56, borderRadius: 14,
                    background: "rgba(253,246,240,0.08)",
                    border: `1px solid ${p.hex}40`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    flexShrink: 0, backdropFilter: "blur(12px)",
                    overflow: "hidden",
                    transition: "transform 0.3s",
                  }}>
                    {p.logo
                      ? <img src={p.logo} alt={p.name} style={{ width: 44, height: 44, objectFit: "contain" }} />
                      : <svg width="18" height="18" viewBox="0 0 18 18" fill="none"><path d="M3 9h12m0 0l-5-5m5 5l-5 5" stroke={p.hex} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    }
                  </div>
                </div>

                <p className="serif" style={{
                  fontSize: 17, fontStyle: "italic", fontWeight: 400,
                  color: p.hex, marginBottom: 16,
                }}>"{p.tagline}"</p>
                <p style={{ fontSize: 14, lineHeight: 1.7, color: "rgba(253,246,240,0.6)", fontWeight: 300, marginBottom: 20 }}>
                  {p.summary}
                </p>

                <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                  {p.category.split("·").map(t => (
                    <span key={t} className="pill-dark" style={{ fontSize: 10, padding: "4px 12px" }}>{t.trim()}</span>
                  ))}
                </div>
              </div>

              <div style={{
                padding: "18px 30px",
                borderTop: "1px solid rgba(253,246,240,0.08)",
                display: "flex", justifyContent: "space-between", alignItems: "center",
                background: "rgba(0,0,0,0.15)",
              }}>
                <span className="mono" style={{ fontSize: 10, color: "rgba(253,246,240,0.4)", letterSpacing: "0.1em", textTransform: "uppercase" }}>
                  {p.hero.split("·")[0]}
                </span>
                <span style={{ fontSize: 12, color: p.hex, fontWeight: 500, letterSpacing: "0.03em" }}>
                  View Case →
                </span>
              </div>
            </div>
          ))}


        </div>
      </div>
    </section>
  );
}

