// SKILLS
// ═══════════════════════════════════════════════════════════════════════════

function Skills() {
  return (
    <section id="skills" style={{ padding: "140px 48px", position: "relative", overflow: "hidden" }} className="pad-side">
      <div className="orb" style={{ width: 600, height: 600, bottom: "-10%", right: "-10%", background: `${C.accent}30` }} />
      <div className="orb" style={{ width: 400, height: 400, top: "10%", left: "-10%", background: `${C.primary}20` }} />

      <div style={{ maxWidth: 1200, margin: "0 auto", position: "relative", zIndex: 2 }}>
        <div style={{ marginBottom: 72, maxWidth: 720 }}>
          <div className="eyebrow" style={{ marginBottom: 24 }}>The Toolkit</div>
          <h2 className="serif" style={{ fontSize: "clamp(40px, 6vw, 72px)", fontWeight: 400, lineHeight: 1.05, marginBottom: 28 }}>
            Built where science<br />
            <span style={{ fontStyle: "italic", background: `linear-gradient(135deg, ${C.primary}, ${C.cta})`, WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>meets product.</span>
          </h2>
          <p style={{ fontSize: "clamp(16px, 1.8vw, 19px)", lineHeight: 1.75, color: C.textSoft, fontWeight: 300 }}>
            Six years of self-learning. One MSc in Behavioural Sciences. Five startups. Two years as a founder. One year as an HR consultant. The toolkit below is what the journey built.
          </p>
        </div>

        {/* Skill categories */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))", gap: 24, marginBottom: 56 }}>
          {SKILLS.map(({ category, type, items }, i) => (
            <div key={category} className="glass-heavy lift" style={{
              padding: "40px 36px",
              animation: `fadeUp 0.8s cubic-bezier(0.16,1,0.3,1) ${0.1 + i * 0.12}s both`,
            }}>
              <div style={{ marginBottom: 32 }}>
                <h3 className="serif" style={{ fontSize: 26, fontWeight: 600, lineHeight: 1.1, color: C.text }}>{category}</h3>
                <div style={{ width: 40, height: 3, background: `linear-gradient(90deg, ${C.primary}, ${C.secondary})`, borderRadius: 2, marginTop: 10 }} />
              </div>

              <div style={{ display: "flex", flexDirection: "column", gap: 18 }}>
                {items.map(s => (
                  <div key={s.name}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                      <span style={{ fontSize: 14, color: C.text, fontWeight: 400 }}>{s.name}</span>
                      <span className="mono" style={{ fontSize: 11, color: C.primary, fontWeight: 500 }}>{s.lvl}%</span>
                    </div>
                    <div style={{ height: 4, background: "rgba(198,93,59,0.1)", borderRadius: 100, overflow: "hidden" }}>
                      <div style={{
                        height: "100%",
                        width: `${s.lvl}%`,
                        background: `linear-gradient(90deg, ${C.primary}, ${C.secondary})`,
                        borderRadius: 100,
                        transition: "width 1s cubic-bezier(0.16,1,0.3,1)",
                      }} />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Big stats glass bar */}
        <div className="glass-heavy" style={{
          padding: "48px 32px",
          display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(140px, 1fr))", gap: 0,
        }}>
          {[
            { n: "6+", l: "Products Built" },
            { n: "100+", l: "Workshops" },
            { n: "2500+", l: "Teams Out-Pitched" },
            { n: "3", l: "IIT/IISc Stages" },
            { n: "1", l: "VC Mentorship" },
            { n: "∞", l: "Curiosity" },
          ].map(({ n, l }, i, arr) => (
            <div key={l} style={{
              padding: "16px 20px", textAlign: "center",
              borderRight: i < arr.length - 1 ? "1px solid rgba(198,93,59,0.12)" : "none",
            }}>
              <div className="serif" style={{
                fontSize: "clamp(36px, 4vw, 56px)",
                fontWeight: 700, lineHeight: 1, marginBottom: 10,
                background: `linear-gradient(135deg, ${C.primary}, ${C.cta})`,
                WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
              }}>{n}</div>
              <div className="mono" style={{ fontSize: 10, color: C.textMute, letterSpacing: "0.12em", textTransform: "uppercase" }}>{l}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

