// MAIN
// ═══════════════════════════════════════════════════════════════════════════

export default function Portfolio() {
  const [page, setPage] = useState("home");
  const [projectId, setProjectId] = useState("cook2you");
  const [pendingScroll, setPendingScroll] = useState(null);

  // Reliable cross-page navigation
  const navigateTo = (sectionId) => {
    if (sectionId === "top") {
      setPage("home");
      window.scrollTo({ top: 0, behavior: "smooth" });
      return;
    }
    const el = document.getElementById(sectionId);
    if (el) {
      el.scrollIntoView({ behavior: "smooth" });
    } else {
      setPendingScroll(sectionId);
      setPage("home");
    }
  };

  useEffect(() => {
    if (!pendingScroll) return;
    const tryScroll = (attempts = 0) => {
      const el = document.getElementById(pendingScroll);
      if (el) {
        el.scrollIntoView({ behavior: "smooth" });
        setPendingScroll(null);
      } else if (attempts < 20) {
        setTimeout(() => tryScroll(attempts + 1), 80);
      }
    };
    tryScroll();
  }, [pendingScroll, page]);

  return (
    <>
      <style>{fontsCSS}</style>
      <style>{globalCSS}</style>
      <div className="bg-fixed" />
      <div className="bg-tint" />
      <GlassFilter />
      <Cursor />
      <Nav setPage={setPage} currentPage={page} navigateTo={navigateTo} />

      {page === "home" && (
        <>
          <PrismaHero />
          <Story />
          <Work setPage={setPage} setProjectId={setProjectId} />
          <Skills />
          <Contact />
        </>
      )}

      {page === "project" && (
        <ProjectPage id={projectId} setPage={setPage} setProjectId={setProjectId} />
      )}

      <PillNav page={page} setPage={setPage} navigateTo={navigateTo} />
    </>
  );
}
